package com.example.offlineshapealarm.alarm
import android.app.*; import android.content.*; import android.os.*; import android.view.*; import android.widget.*
class AlarmActivity: Activity(){ private var start=0L; private val handler=Handler(Looper.getMainLooper()); private lateinit var progress:ProgressBar; private lateinit var hold:Button; private var alarmId:String=""
 override fun onCreate(b:Bundle?){ super.onCreate(b); alarmId=intent.getStringExtra("alarmId") ?: ""; if(Build.VERSION.SDK_INT>=27){ setShowWhenLocked(true); setTurnScreenOn(true) } else @Suppress("DEPRECATION") window.addFlags(WindowManager.LayoutParams.FLAG_SHOW_WHEN_LOCKED or WindowManager.LayoutParams.FLAG_TURN_SCREEN_ON); val label=intent.getStringExtra("label") ?: "Alarm"; val root=LinearLayout(this).apply{ orientation=LinearLayout.VERTICAL; gravity=Gravity.CENTER; setPadding(48,48,48,48) }; root.addView(TextView(this).apply{text=label; textSize=30f; gravity=Gravity.CENTER}); root.addView(TextView(this).apply{text="Temporary challenge: hold the button for five seconds to dismiss."; gravity=Gravity.CENTER}); progress=ProgressBar(this,null,android.R.attr.progressBarStyleHorizontal).apply{max=5000}; root.addView(progress, LinearLayout.LayoutParams(-1,-2)); hold=Button(this).apply{text="Hold to dismiss"}; root.addView(hold); val emergency=Button(this).apply{text="Emergency override: hold 10 seconds"}; root.addView(emergency); setContentView(root); wire(hold,5000,"long-press"); wire(emergency,10000,"emergency-override") }
 private fun wire(button:Button, required:Long, reason:String){ val tick=object:Runnable{ override fun run(){ val elapsed=System.currentTimeMillis()-start; progress.max=required.toInt(); progress.progress=elapsed.toInt(); if(elapsed>=required){ stop(reason) } else handler.postDelayed(this,50) } }; button.setOnTouchListener{_,e -> when(e.action){ MotionEvent.ACTION_DOWN -> { start=System.currentTimeMillis(); handler.post(tick); true }; MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> { handler.removeCallbacks(tick); progress.progress=0; true }; else -> false } } }
 private fun stop(reason:String){ handler.removeCallbacksAndMessages(null); startService(Intent(this, AlarmForegroundService::class.java).setAction(AlarmForegroundService.ACTION_STOP_ALARM).putExtra("alarmId",alarmId).putExtra("reason",reason)); finish() }
}
